struct Tokenizer {
    source: String,
    line_pos: usize,
}

impl Tokenizer {
    fn new(input: String) -> Tokenizer {
        Tokenizer { source: input, line_pos: 0 }
    }

    fn next_line(&mut self) -> Option<&str> {
        let remaining = &self.source[self.line_pos..];
        if remaining.is_empty() {
            return None;
        }
        match remaining.find('\n') {
            Some(i) => {
                let line = &self.source[self.line_pos..self.line_pos + i];
                self.line_pos += i + 1;
                Some(line)
            }
            None => {
                let line = &self.source[self.line_pos..];
                self.line_pos = self.source.len();
                Some(line)
            }
        }
    }
}

fn main() {
    let mut tok = Tokenizer::new(String::from("line1\nline2"));
    println!("{:?}", tok.next_line());
    println!("{:?}", tok.next_line());
}

