use std::rc::Rc;
use std::cell::RefCell;

type NodeRef = Rc<RefCell<Node>>;

struct Node {
    value: i32,
    parent: Option<NodeRef>,
    children: Vec<NodeRef>,
}

fn make_root(value: i32) -> NodeRef {
    Rc::new(RefCell::new(Node { value, parent: None, children: vec![] }))
}

fn add_child(parent: &NodeRef, value: i32) -> NodeRef {
    let child = Rc::new(RefCell::new(Node {
        value,
        parent: Some(Rc::clone(parent)),
        children: vec![],
    }));
    parent.borrow_mut().children.push(Rc::clone(&child));
    child
}

fn main() {
    let root = make_root(1);
    let child = add_child(&root, 42);
    println!("child={}, parent={}", child.borrow().value,
        child.borrow().parent.as_ref().unwrap().borrow().value);
}

