use std::pin::Pin;
use std::marker::PhantomPinned;

struct SelfRef {
    data: String,
    ptr: *const String,
    _pin: PhantomPinned,
}

impl SelfRef {
    fn new(data: String) -> Pin<Box<Self>> {
        let s = SelfRef { data, ptr: std::ptr::null(), _pin: PhantomPinned };
        let mut boxed = Box::pin(s);
        let ptr = &boxed.data as *const String;
        unsafe { boxed.as_mut().get_unchecked_mut().ptr = ptr; }
        boxed
    }

    fn data(self: Pin<&Self>) -> &str {
        &self.get_ref().data
    }
}

fn main() {
    let pinned = SelfRef::new(String::from("hello"));
    // Access through a pinned reference — never move out
    println!("{}", pinned.as_ref().data());
}
